import os,time,json,fnmatch
p=json.loads(os.environ.get('__EXECUTOR_INPUT__','{}'))
root=p.get('path','.');dur=int(p.get('duration_secs',5))
max_depth=int(p.get('max_depth',10))
ign=['.git/*','node_modules/*','target/*','__pycache__/*','.DS_Store']
def ig(x):
 rel=os.path.relpath(x,root)
 return any(fnmatch.fnmatch(rel,i) or fnmatch.fnmatch(os.path.basename(x),i) for i in ign)
def walk_limited(path,depth=0):
 if depth>max_depth:return
 try:
  for dp,dn,fn in os.walk(path):
   if ig(dp):dn.clear();continue
   rel_depth=dp[len(path):].count(os.sep)
   if rel_depth>max_depth:dn.clear();continue
   for f in fn:
    fp=os.path.join(dp,f)
    if not ig(fp):yield fp
 except:pass
init={}
for fp in walk_limited(root):
 try:init[fp]=os.path.getmtime(fp)
 except:pass
ev=[];start=time.time()
while time.time()-start<dur:
 time.sleep(0.5);cur={}
 for fp in walk_limited(root):
  try:
   m=os.path.getmtime(fp);cur[fp]=m
   if fp not in init:ev.append({'type':'created','path':fp})
   elif m!=init[fp]:ev.append({'type':'modified','path':fp})
  except:pass
 for fp in list(init):
  if fp not in cur and not os.path.exists(fp):ev.append({'type':'deleted','path':fp});init.pop(fp,None)
 init.update(cur)
print(json.dumps({'events':ev,'count':len(ev),'max_depth':max_depth},ensure_ascii=False))

