import os,time,json,subprocess,fnmatch
p=json.loads(os.environ.get('__EXECUTOR_INPUT__','{}'))
root=p.get('path','.');dur=int(p.get('duration_secs',5));pat=p.get('pattern','')
ign=['.git/*','node_modules/*','target/*','__pycache__/*']
def ig(x):
 rel=os.path.relpath(x,root)
 return any(fnmatch.fnmatch(rel,i) for i in ign)
init={}
for dp,dn,fn in os.walk(root):
 if ig(dp):dn.clear();continue
 for f in fn:
  fp=os.path.join(dp,f)
  if not ig(fp):
   try:init[fp]=os.path.getmtime(fp)
   except:pass
events=[];start=time.time()
while time.time()-start<dur:
 time.sleep(0.5)
 for dp,dn,fn in os.walk(root):
  if ig(dp):dn.clear();continue
  for f in fn:
   fp=os.path.join(dp,f)
   if ig(fp):continue
   try:
    m=os.path.getmtime(fp)
    if fp not in init:events.append({'type':'created','path':fp})
    elif m!=init[fp]:events.append({'type':'modified','path':fp})
    init[fp]=m
   except:pass
if pat and events:
 changed=[e['path'] for e in events if e['type'] in ('created','modified')]
 for fp in changed[:5]:
  r=subprocess.run(['rg','--line-number',pat,fp],capture_output=True,text=True,timeout=5)
  if r.stdout:events.append({'type':'search_match','path':fp,'matches':r.stdout[:500]})
print(json.dumps({'events':events,'count':len(events)},ensure_ascii=False))

